SELECT B1.* FROM ( SELECT A1.* , ROW_NUMBER() OVER() AS PAGEINDEX FROM ( SELECT req.REQUEST_NO AS requestNo, /* 요청번호 */ req.REQUEST_NO AS hiddenRequestNo, (SELECT COMPANY_NM FROM DOCS_COMPANY company WHERE company.COMPANY_CD = req.DEPLOY_COMPANY_CD) AS deployCompanyNm, req.DEPLOY_COMPANY_CD AS deployCompanyCd, /* 배포업체 */ CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = #{sessionLang}) WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = #{sessionLang}) ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = #{sessionLang}) END AS distributeMethodNm, /* 배포방식 */ req.REQUEST_PURPOSE AS requestPurpose, /* 용도 */ req.INSERT_USER_CD AS requestUserCd, /* 요청자 */ reqUser.USER_NM AS requestUserNm, /* 요청자 */ TO_CHAR(req.INSERT_DT, 'YYYY-MM-DD') AS requestDt, /* 요청일 */ (SELECT MAX(TO_CHAR(TO_DATE(fileInfo.USE_END_YMD, 'YYYYMMDD'), 'YYYY-MM-DD')) FROM DOCS_REQUEST_FILE fileInfo WHERE fileInfo.REQUEST_NO = req.REQUEST_NO) AS useEndYmd, /* 유효기간 */ accUser.USER_CD AS purchaserUserCd, accUser.USER_NM AS purchaserUserNm, /* 구매담당자 */ req.BUSINESS_AREA_CD AS businessAreaCd, /* 사업장 */ req.STATUS_CD AS statusCd, /* 상태 */ req.OBJECT_TYPE AS objectType, companyUser.USER_CD AS companyUserCd, /* 업체담당자 */ companyUser.USER_NM AS companyUserNm, /* 업체담당자 */ (SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = req.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT') AS deployUserNm /* 배포자 */ FROM DOCS_REQUEST req INNER JOIN DOCS_REQUEST_DETAIL accDetail ON accDetail.REQUEST_NO = req.REQUEST_NO AND accDetail.APPROVAL_STATUS_CD = 'ACCEPT' INNER JOIN DOCS_USER accUser ON accUser.USER_CD = accDetail.ORIGINAL_USER_CD INNER JOIN DOCS_USER reqUser ON reqUser.USER_CD = req.INSERT_USER_CD INNER JOIN DOCS_REQUEST_DETAIL appDetail ON appDetail.REQUEST_NO = req.REQUEST_NO AND appDetail.APPROVAL_STATUS_CD = 'APPROVAL' INNER JOIN DOCS_REQUEST_DETAIL currDetail ON currDetail.REQUEST_NO = req.REQUEST_NO AND currDetail.PROCESS_SEQ = req.CURRENT_PROCESS_SEQ_NO INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = req.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD WHERE REQUEST_TYPE = 'NO-REG' AND currDetail.APPROVAL_STATUS_CD = 'APPROVAL' AND req.STATUS_CD = 'REQUEST' AND currDetail.ACTUAL_USER_CD = #{sessionUser.userCd} /* 내가 승인해야 할 목록 */
ORDER BY requestDt DESC, requestNo DESC
ORDER BY ${sortColumn} ${order}, requestNo ${order}
) A1 WHERE 1=1
AND requestNo = #{requestNo}
AND deployCompanyCd = #{deployCompanyCd}
AND objectNm = #{objectNm}
AND requestUserCd = #{requestUserCd}
AND businessAreaCd = #{businessAreaCd}
AND statusCd = #{statusCd}
AND objectType = #{objectType}
AND requestDt BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
LIMIT #{end}
) B1
WHERE PAGEINDEX >= #{start}

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT B1.* FROM ( SELECT A1.* FROM ( SELECT req.REQUEST_NO AS requestNo, /* 요청번호 */ req.REQUEST_NO AS hiddenRequestNo, (SELECT COMPANY_NM FROM DOCS_COMPANY company WHERE company.COMPANY_CD = req.DEPLOY_COMPANY_CD) AS deployCompanyNm, req.DEPLOY_COMPANY_CD AS deployCompanyCd, /* 배포업체 */ CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = #{sessionLang}) WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = #{sessionLang}) ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = #{sessionLang}) END AS distributeMethodNm, /* 배포방식 */ req.REQUEST_PURPOSE AS requestPurpose, /* 용도 */ req.INSERT_USER_CD AS requestUserCd, /* 요청자 */ reqUser.USER_NM AS requestUserNm, /* 요청자 */ TO_CHAR(req.INSERT_DT, 'YYYY-MM-DD') AS requestDt, /* 요청일 */ (SELECT MAX(TO_CHAR(TO_DATE(fileInfo.USE_END_YMD, 'YYYYMMDD'), 'YYYY-MM-DD')) FROM DOCS_REQUEST_FILE fileInfo WHERE fileInfo.REQUEST_NO = req.REQUEST_NO) AS useEndYmd, /* 유효기간 */ accUser.USER_CD AS purchaserUserCd, accUser.USER_NM AS purchaserUserNm, /* 구매담당자 */ req.BUSINESS_AREA_CD AS businessAreaCd, /* 사업장 */ req.STATUS_CD AS statusCd, /* 상태 */ req.OBJECT_TYPE AS objectType, companyUser.USER_CD AS companyUserCd, /* 업체담당자 */ companyUser.USER_NM AS companyUserNm, /* 업체담당자 */ (SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = req.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT') AS deployUserNm /* 배포자 */ FROM DOCS_REQUEST req INNER JOIN DOCS_REQUEST_DETAIL accDetail ON accDetail.REQUEST_NO = req.REQUEST_NO AND accDetail.APPROVAL_STATUS_CD = 'ACCEPT' INNER JOIN DOCS_USER accUser ON accUser.USER_CD = accDetail.ORIGINAL_USER_CD INNER JOIN DOCS_USER reqUser ON reqUser.USER_CD = req.INSERT_USER_CD INNER JOIN DOCS_REQUEST_DETAIL appDetail ON appDetail.REQUEST_NO = req.REQUEST_NO AND appDetail.APPROVAL_STATUS_CD = 'APPROVAL' INNER JOIN DOCS_REQUEST_DETAIL currDetail ON currDetail.REQUEST_NO = req.REQUEST_NO AND currDetail.PROCESS_SEQ = req.CURRENT_PROCESS_SEQ_NO INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = req.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD WHERE REQUEST_TYPE = 'NO-REG' AND currDetail.APPROVAL_STATUS_CD = 'APPROVAL' AND req.STATUS_CD = 'REQUEST' AND currDetail.ACTUAL_USER_CD = #{sessionUser.userCd} /* 내가 승인해야 할 목록 */ ) A1 WHERE 1=1
AND requestNo = #{requestNo}
AND deployCompanyCd = #{deployCompanyCd}
AND objectNm = #{objectNm}
AND requestUserCd = #{requestUserCd}
AND businessAreaCd = #{businessAreaCd}
AND statusCd = #{statusCd}
AND objectType = #{objectType}
AND requestDt BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
) B1 ) C1

