/* 최종 승인에 추가할 아이템 리스트 조회 */
SELECT unreg.OBJECT_ID AS objectId,
	   fileInfo.FILE_NO AS fileNo
FROM DOCS_UNREG_INFO unreg
		 JOIN DOCS_FILE fileInfo ON unreg.FILE_CD = fileInfo.FILE_CD
WHERE (OBJECT_ID, FILE_NO) IN (
	SELECT OBJECT_ID, FILE_NO
	FROM DOCS_REQUEST_FILE
	WHERE REQUEST_NO = #{requestNo}
)
